mapper.select:
select 
from t_r_workflow_instance
where workspace_id = #{workspaceId}
  and workflow_definition_code = #{workflowDefinitionCode}
  and id = #{id}
limit 1

select 
from t_r_workflow_instance
where workflow_definition_code = #{workflowDefinitionCode}

    and started_at  >=  #{start}


    and started_at  <=  #{end}

order by started_at desc
limit 1

select from t_r_workflow_instance where workflow_definition_code = #{workflowDefinitionCode}
and name like concat('%', #{searchVal}, '%')
order by created_at desc

select from t_r_workflow_instance where workflow_definition_code in
#{code}
order by created_at desc

select 
from t_r_workflow_instance
where project_code = #{projectCode}

    and name like concat('%', #{searchVal}, '%')


    and status = #{status}

order by created_at desc

select 
from t_r_workflow_instance
where owner_host = #{ownerHost}
  and status = #{status}

mapper.update:
update t_r_workflow_instance
set owner_host = #{newOwner}
where id = #{id}
  and owner_host = #{oldOwner}
  and status = #{status}
